function max_coins(balloons) {
    const n = balloons.length;
    const nums = [1, ...balloons, 1];
    const dp = Array.from({length:n+2}, () => new Array(n+2).fill(0));
    for (let len=1;len<=n;len++) {
        for (let left=1;left+len-1<=n;left++) {
            const right=left+len-1;
            for (let k=left;k<=right;k++) {
                const coins = nums[left-1]*nums[k]*nums[right+1] + dp[left][k-1] + dp[k+1][right];
                if (coins>dp[left][right]) dp[left][right]=coins;
            }
        }
    }
    return dp[1][n];
}

function max_area(heights) {
    let lo=0, hi=heights.length-1, best=0;
    while (lo<hi) {
        const area = Math.min(heights[lo],heights[hi]) * (hi-lo);
        if (area > best) best = area;
        if (heights[lo] < heights[hi]) lo++; else hi--;
    }
    return best;
}

function dijkstra(adj, n) {
    const INF = Infinity;
    const dist = new Array(n).fill(INF); dist[0] = 0;
    const visited = new Array(n).fill(false);
    for (let iter=0;iter<n;iter++) {
        let u = -1, best = INF;
        for (let i=0;i<n;i++) if (!visited[i] && dist[i] < best) { best = dist[i]; u = i; }
        if (u === -1) break;
        visited[u] = true;
        for (const [v, w] of adj[u]) { if (dist[u] + w < dist[v]) dist[v] = dist[u] + w; }
    }
    const out = dist.map(d => d === INF ? -1 : d);
    return out;
}

function first_occurrence(nums, target) {
    let lo = 0, hi = nums.length-1, ans = -1;
    while (lo <= hi) {
        const mid = (lo+hi) >> 1;
        if (nums[mid] === target) { ans = mid; hi = mid-1; }
        else if (nums[mid] < target) lo = mid+1; else hi = mid-1;
    }
    return ans;
}

function hamming_distance(x, y) {
    let v = (x ^ y) >>> 0; let count = 0;
    while (v !== 0) { count += v & 1; v = v >>> 1; }
    return count;
}

function can_jump(nums) {
    let reach = 0;
    for (let i=0;i<nums.length;i++) { if (i > reach) break; reach = Math.max(reach, i + nums[i]); }
    return reach >= nums.length - 1;
}

function has_cycle(values, pos) {
    if (pos<0 || values.length===0) return false;
    const n=values.length;
    let slow=0, fast=0;
    function nxt(i) { return i+1<n ? i+1 : pos; }
    do {
        slow=nxt(slow); fast=nxt(nxt(fast));
    } while (slow!==fast);
    return true;
}

function longest_k_distinct(s, k) {
    if (k===0) return 0;
    const freq={}; let left=0, best=0, distinct=0;
    for (let right=0;right<s.length;right++) {
        const ch=s[right]; if (!freq[ch]) { freq[ch]=0; }
        if (freq[ch]===0) distinct++;
        freq[ch]++;
        while (distinct>k) { const lc=s[left]; freq[lc]--; if (freq[lc]===0) distinct--; left++; }
        best=Math.max(best, right-left+1);
    }
    return best;
}

function count_palindromic_substrings(s) {
    let count=0;
    function expand(l,r) { let c=0; while (l>=0 && r<s.length && s[l]===s[r]) { c++; l--; r++; } return c; }
    for (let i=0;i<s.length;i++) { count+=expand(i,i); count+=expand(i,i+1); }
    return count;
}

function min_meeting_rooms(starts, ends) {
    const s=starts.slice().sort((a,b)=>a-b), e=ends.slice().sort((a,b)=>a-b);
    let rooms=0, best=0, si=0, ei=0;
    while (si<s.length) {
        if (s[si]<e[ei]) { rooms++; si++; best=Math.max(best,rooms); }
        else { rooms--; ei++; }
    }
    return best;
}

function min_knight_moves(x, y) {
    x=Math.abs(x); y=Math.abs(y);
    const moves=[[1,2],[2,1],[-1,2],[-2,1],[1,-2],[2,-1],[-1,-2],[-2,-1]];
    const visited=new Set(['0,0']); let q=[[0,0,0]]; let qi=0;
    while (qi<q.length) {
        const [cx,cy,d]=q[qi]; qi++;
        if (cx===x && cy===y) return d;
        for (const [dx,dy] of moves) {
            const nx=cx+dx, ny=cy+dy;
            if (nx>=-2 && ny>=-2 && nx<=x+2 && ny<=y+2) {
                const key=nx+','+ny;
                if (!visited.has(key)) { visited.add(key); q.push([nx,ny,d+1]); }
            }
        }
    }
    return -1;
}

function hamming_weight(n) {
    let count = 0; let x = n >>> 0;
    while (x !== 0) { count += x & 1; x = x >>> 1; }
    return count;
}

function lps(s) {
    const n=s.length;
    const dp = Array.from({length:n}, () => new Array(n).fill(0));
    for (let i=n-1;i>=0;i--) {
        dp[i][i]=1;
        for (let j=i+1;j<n;j++) {
            if (s[i]===s[j]) dp[i][j]=dp[i+1][j-1]+2;
            else dp[i][j]=Math.max(dp[i+1][j], dp[i][j-1]);
        }
    }
    return (n===0?0:dp[0][n-1]);
}

function restore_ip_count(s) {
    const n=s.length; let count=0;
    function valid(seg) {
        if (seg.length===0 || seg.length>3) return false;
        if (seg.length>1 && seg[0]==='0') return false;
        return parseInt(seg,10)<=255;
    }
    for (let i=1;i<=3 && i<n;i++) {
        for (let j=i+1;j<=i+3 && j<n;j++) {
            for (let k=j+1;k<=j+3 && k<n;k++) {
                const p1=s.slice(0,i), p2=s.slice(i,j), p3=s.slice(j,k), p4=s.slice(k);
                if (valid(p1) && valid(p2) && valid(p3) && valid(p4)) count++;
            }
        }
