}

function subset_sum(nums, target) {
    const dp = new Array(target+1).fill(false); dp[0]=true;
    for (const x of nums) for (let i=target;i>=x;i--) if (dp[i-x]) dp[i]=true;
    return dp[target]?true:false;
}

function minimum_total(triangle) {
    const n=triangle.length;
    const dp=triangle[n-1].slice();
    for (let i=n-2;i>=0;i--) {
        for (let j=0;j<=i;j++) dp[j]=triangle[i][j]+Math.min(dp[j],dp[j+1]);
    }
    return dp[0];
}

function is_valid(s) {
    const stack = []; const pairs = {')':'(', ']':'[', '}':'{'};
    for (const ch of s) {
        if (ch==='('||ch==='['||ch==='{') stack.push(ch);
        else { if (stack.length===0 || stack.pop() !== pairs[ch]) return false; }
    }
    return stack.length === 0;
}
